"use client"
import { useState } from "react"

export default function VehicleManager() {
  const [vehicles, setVehicles] = useState<any[]>([])
  const [form, setForm] = useState({
    name: "",
    plate: "",
    location: "",
    content: ""
  })

  const addVehicle = () => {
    if (!form.name) return
    setVehicles([...vehicles, { ...form }])
    setForm({ name: "", plate: "", location: "", content: "" })
  }

  return (
    <div>
      <h2 className="text-2xl font-bold mb-4">🚗 Fahrzeuge</h2>

      <div className="grid grid-cols-2 gap-4 mb-6">
        <input placeholder="Name" value={form.name} onChange={e => setForm({ ...form, name: e.target.value })} />
        <input placeholder="Kennzeichen" value={form.plate} onChange={e => setForm({ ...form, plate: e.target.value })} />
        <input placeholder="Standort" value={form.location} onChange={e => setForm({ ...form, location: e.target.value })} />
        <input placeholder="Inhalt" value={form.content} onChange={e => setForm({ ...form, content: e.target.value })} />

        <button onClick={addVehicle} className="bg-purple-600 p-2 rounded">
          ➕ Fahrzeug hinzufügen
        </button>
      </div>

      <div className="grid gap-4">
        {vehicles.map((v, i) => (
          <div key={i} className="border p-4 rounded bg-black/30">
            <h3>{v.name}</h3>
            <p>Kennzeichen: {v.plate}</p>
            <p>Standort: {v.location}</p>

            <input
              value={v.content}
              onChange={(e) => {
                const newV = [...vehicles]
                newV[i].content = e.target.value
                setVehicles(newV)
              }}
            />
          </div>
        ))}
      </div>
    </div>
  )
}
