"use client"
import { useState } from "react"

export default function ItemTable() {
  const [items, setItems] = useState<any[]>([])
  const [form, setForm] = useState({
    name: "",
    price: "",
    image: "",
    amount: ""
  })

  const addItem = () => {
    if (!form.name) return
    setItems([...items, { ...form }])
    setForm({ name: "", price: "", image: "", amount: "" })
  }

  return (
    <div className="mb-20">
      <h2 className="text-2xl font-bold mb-4">📦 Item Lager</h2>

      <div className="grid grid-cols-2 gap-4 mb-6">
        <input placeholder="Name" value={form.name} onChange={e => setForm({ ...form, name: e.target.value })} />
        <input placeholder="Preis" value={form.price} onChange={e => setForm({ ...form, price: e.target.value })} />
        <input placeholder="Bild URL" value={form.image} onChange={e => setForm({ ...form, image: e.target.value })} />
        <input placeholder="Anzahl" value={form.amount} onChange={e => setForm({ ...form, amount: e.target.value })} />

        <button onClick={addItem} className="bg-purple-600 p-2 rounded">
          ➕ Item hinzufügen
        </button>
      </div>

      <div className="grid gap-4">
        {items.map((item, i) => (
          <div key={i} className="border p-4 rounded bg-black/30">
            <img src={item.image} className="h-32 object-cover mb-2" />
            <h3>{item.name}</h3>
            <p>Preis: {item.price}</p>
            <input
              value={item.amount}
              onChange={(e) => {
                const newItems = [...items]
                newItems[i].amount = e.target.value
                setItems(newItems)
              }}
            />
          </div>
        ))}
      </div>
    </div>
  )
}
